mapper.select:
SELECT * FROM place
WHERE source = #{source} AND external_ref = #{externalRef}
LIMIT 1

mapper.update:
UPDATE place
SET latitude = #{latitude},
    longitude = #{longitude}
WHERE id = #{id}
  AND (
    latitude IS NULL OR longitude IS NULL
    OR latitude <> #{latitude}
    OR longitude <> #{longitude}
  )

mapper.select:
SELECT id FROM place
WHERE name = #{name}
  AND address = #{address}
  AND city = #{city}
  AND ( (district IS NULL AND #{district} IS NULL) OR district = #{district} )
  AND country = #{country}
LIMIT 1
